sql:
SELECT DISTINCT u.username
FROM users u
JOIN comments c ON u.user_id = c.user_id;

SELECT likes.like_id, dweets.dweet_text
FROM likes
JOIN dweets ON likes.dweet_id = dweets.dweet_id;

SELECT COUNT(*) as num_followers
FROM follows
WHERE followed_id = 5;

SELECT COUNT(*) AS likes_received
FROM likes
WHERE user_id = 1 AND STRFTIME('%Y-%m-%d', created_at) = '2021-04-18';

SELECT DISTINCT u.user_id, u.username
FROM users u
JOIN dweets d ON u.user_id = d.user_id;

SELECT COUNT(*) 
FROM reporting 
WHERE user_id = (SELECT user_id FROM users WHERE username = 'user1');

SELECT COUNT(*)
FROM users
WHERE user_id NOT IN (
  SELECT DISTINCT user_id
  FROM comments
);

SELECT users.username
FROM users
WHERE users.user_id NOT IN (SELECT user_id FROM reporting);

external_knowledge:
- 'enigmatic spark of appreciation' refers to the like;
- 'captured by its time and kindling heart' refers to the timestamp and user who made the like;
- 'illuminate this particular dweet' refers to the action of liking a specific dweet identified by 'some_dweet_id';
- 'realm of digital echoes' is a metaphorical reference to the platform or database where dweets and likes are stored;

sql:
SELECT AVG(likes_count) 
FROM (
  SELECT COUNT(*) AS likes_count 
  FROM likes 
  GROUP BY dweet_id
) AS dweet_likes;

SELECT dweet_text, created_at
FROM dweets
WHERE dweet_id = 0;

SELECT DISTINCT users.user_id, users.username
FROM users
INNER JOIN dweets ON users.user_id = dweets.user_id;

SELECT COUNT(n.notification_id) / COUNT(DISTINCT u.user_id) AS avg_notifications_per_user
FROM users u
LEFT JOIN notifications n ON u.user_id = n.user_id;

SELECT COUNT(user_id) AS active_users_count
FROM (
    SELECT user_id FROM dweets
    UNION
    SELECT user_id FROM likes
) AS active_users;

SELECT user_id FROM likes
INTERSECT
SELECT user_id FROM comments;

SELECT follower_id, followed_id 
FROM follows 
WHERE follow_id > 0;
